INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-a5729396-moex-00294', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「從網壇傳奇費德勒的成熟過程裡，可看到他是怎麼開始要求自己不要再情緒失控，不要再亂摔球拍， 尋求心理專家的協助，逐漸長成如今世人熟悉的紳士樣貌。我甚至敢說，如今他是網球運動的優雅代 名詞，在最具傳統的英國溫布敦的中央球場，以技術和風度，拿下一盤又一盤，讓世人仰望。他有過 的掙扎，讓我更理解他，並喜愛他。原來，翩翩君子，不是天生。」 根據上文，作者藉由觀察費德勒得到的省思，何者最適當？', '["心理專家才是優雅形象的推手", "成為紳士仍然會出現情緒問題", "技術和風度都需要後天的鍛鍊", "想成為傳奇就不該執著於勝敗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00295', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「一位印地安老人告訴他的孫子：『孩子，人們的內心一直有兩匹狼的爭戰。其中一匹代表邪惡，牠 是憤怒、嫉妒、猜忌、懊悔、貪婪、傲慢、自怨自艾、罪惡感、謊言、虛榮心、優越感和自負。另一 匹代表良善，牠是歡樂、平和、愛、希望、從容、謙卑、寬容、同理心、慷慨、憐憫和信念。』孫子 問祖父：『那一匹狼贏了？』祖父回答：『你餵養的那一匹。』」 根據上文，祖父想提醒孫子的重點，最適切的是：', '["如何讓善惡平衡共存是重要的修為", "自己會成為什麼樣子是操之在己的", "良善或邪惡的定義沒有必然的標準", "惡念往往起於善的需求沒有被滿足"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00296', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「許多有影響力的人，於其冠冕堂皇的言說背後，另有一套不守法、不講公正、專事鑽營的規矩，甚 至因此而飛黃騰達。人們一旦耳濡目染於此等處世行事的範例，見識到這套未明言的知識如何強而有 力，自然便不再信任表面上的理論與說法了。」 根據上文，下列選項何者最符合文意？', '["徒仗空言而昧於行事", "理論比行動具影響力", "滿口道理不如好榜樣", "學道容易然踐行困難"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00297', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「油芒是瀕臨絕跡的臺灣特有植物，抗旱、耐鹽，加上營養豐富，全株可用作循環經濟。現在氣候變 遷議題獲得各界關心，油芒是三年生作物，每次收成只需要從莖桿部切除後，就可以再次生長，只需 要三年翻一次土，減少原先在土壤中的碳被釋放到大氣層。相較於水稻100至120天、小麥約半年就 需要犁田一次，更具固碳效果。」 根據上文，臺灣油芒被譽為「超級未來食物」的主要原因是什麼？', '["口感美味有助外銷歐美", "能適應土壤惡劣的特性", "比米麥的產量高上許多", "可以節省更多肥料支出"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00298', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「世界上大多數國家的著作權法，皆是大量的國際條約和貿易協定影響下的結果，在今日這種情形更 勝於以往，不過多數國家也額外各自制定和詮釋相關的法條。本書將儘可能指出歐盟內存在的差異， 在相關的討論中，也會常提及美國的相關案例，當網路的便利性使得跨國工作更為常見的情況下，創 作者極有可能需要同時面對不同的法律體系。」 根據上文，下列選項何者最接近作者撰文目的？', '["提醒讀者各國法律分歧，跨國工作環境日益嚴峻", "檢討各國著作權法律有所異同，應尋求一致標準", "提醒讀者留心國際條約和貿易協定的最大公約數", "針對目前全球化趨勢，協助創作者維護自身權益"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00299', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「全世界會排放大量的溫室氣體，是因為目前使用的能源技術是最便宜的。大部分零碳方案都比採用 化石燃料的成本高，部分原因是化石燃料的價格沒有反映出它所造成的環境破壞，才會看起來比替代 能源便宜。當為了追求零碳排放目標時多支付的價格，比爾蓋茲稱之為『綠色溢價』，所以努力降低 『綠色溢價』到可接受的程度，成為達成『零碳排放』的首要目標。而『綠色溢價』提供我們不同的 視角，幫助我們檢視： 1、綠色溢價低的方案，未見實施：價格不是障礙，必有其他因素妨礙方案大規模推向市場，例如過 時的公共政策，或者環保意識不足。 2、綠色溢價過高的方案，無法實施：選擇環保選項的額外成本，遲遲無法去碳化，需要大量資金投 入，開發新技術、新產品，以降低成本。 3、各國扮演的角色：研發能力強的國家致力於開發新產品，使價格更便宜，然後出口到付不起目前 溢價的地區。如此，就不必爭論是否各國都承擔了該承擔的義務來避免氣候災難。」 根據上文，下列選項有關「綠色溢價」的說明何者正確？', '["綠色溢價的計算，只與化石燃油的價格相關", "綠色溢價高低，與資源投入、產品創新有關", "綠色溢價愈低，代表無利可圖，企業興趣缺缺", "綠色溢價愈高，將可鼓勵企業，努力追求獲利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00300', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '承上題，下列選項何者正確？', '["開發中國家，可豁免氣候災難的責任", "零碳排放，未必都得付出更多的代價", "環保政策的成敗，節能是重要的因素", "除了環保，經濟成本也是考量的關鍵"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00301', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '甲以乙為被告，向臺灣嘉義地方法院起訴，請求乙給付買賣價金新臺幣100萬元。關於管轄，下列敘 述何者錯誤？', '["若乙住所地為嘉義市，則臺灣嘉義地方法院為有管轄權之法院", "若甲、乙於買賣契約中約定債務履行地為嘉義市，則臺灣嘉義地方法院為有管轄權之法院", "若臺灣嘉義地方法院無管轄權，惟乙不抗辯該法院無管轄權並為本案之言詞辯論時，該法院即有管轄權", "若臺灣嘉義地方法院無管轄權，法院僅得依甲之聲請以裁定移送至有管轄權之法院，不得依職權為 移送之裁定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00302', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '甲主張乙詐領其存款新臺幣200萬元，至臺灣臺北地方法院起訴請求乙如數返還，分由該法院民事庭 A法官獨任審理，於審理期間，因甲年老不善陳述，偕同其子丙為輔佐人到庭。關於法官迴避，下列 敘述何者正確？', '["如A於分案後4個月均未實質進行本件訴訟，即屬未勤勉、妥速執行職務而有偏頗之虞，甲及乙均得 聲請A迴避", "如A執行職務有偏頗之虞，丙雖為輔佐人，亦得於言詞辯論時，經在場之甲同意，聲請法官迴避", "如乙以A未准許其證據調查聲請為由聲請法官迴避時，為免臺灣臺北地方法院陷於利害衝突、難以 公平審理，得向直接上級法院即臺灣高等法院聲請", "如甲於收受本件訴訟終局判決時，始發現乙曾為A在大學兼任教職時之學生，甲即得認為A執行職 務有偏頗之虞而聲請法官迴避"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00303', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-1611a566', 'sub-aboriginal-a5729396-03', NULL, 'single_choice', '下列何種情形，被告無當事人能力？', '["A對在我國營業之外國公司B起訴", "A對B公司之分公司就其業務範圍內之事項起訴", "A對設有代表人之非法人團體B起訴", "A於民國108年9月1日對B起訴，而B已於同年6月30日死亡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
